package agentd

import (
	"context"
	"time"

	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/controller"

	corev1 "k8s.io/api/core/v1"
	k8serrors "k8s.io/apimachinery/pkg/api/errors"
)

const (
	SessionExpirationTimeout  = 15 * time.Minute
	LastActivityAnnotationKey = "agentcube.volcano.sh/last-activity"
)

type Reconciler struct {
	Client    client.Client
	APIReader client.Reader
}

func NewSandboxCleanupReconciler(client client.Client) *Reconciler {
	return &Reconciler{
		Client:    client,
		APIReader: client,
	}
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	sandbox := &corev1.Pod{}
	if err := r.APIReader.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if k8serrors.IsNotFound(err) {
			return ctrl.Result{}, nil
		}
		return ctrl.Result{}, err
	}

	lastActivityStr, exists := sandbox.Annotations[LastActivityAnnotationKey]
	if !exists || lastActivityStr == "" {
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		return ctrl.Result{RequeueAfter: 30 * time.Second}, err
	}

	expiration := lastActivity.Add(SessionExpirationTimeout)

	if time.Now().After(expiration) {
		if err := r.Client.Delete(ctx, sandbox); err != nil {
			if !k8serrors.IsNotFound(err) {
				return ctrl.Result{}, err
			}
		}
		return ctrl.Result{}, nil
	}

	requeueAfter := time.Until(expiration)
	if requeueAfter <= 0 {
		requeueAfter = 1 * time.Second
	}

	return ctrl.Result{RequeueAfter: requeueAfter}, nil
}

func (r *Reconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&corev1.Pod{}).
		WithOptions(controller.Options{MaxConcurrentReconciles: 1}).
		Complete(r)
}

