package services

import (
	"archive/tar"
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"time"

	"github.com/docker/docker/api/types"
	"github.com/docker/docker/api/types/filters"
	"github.com/docker/docker/client"
)

type DockerService struct {
	cli *client.Client
}

func NewDockerService() (*DockerService, error) {
	ctx := context.Background()
	cli, err := client.NewClientWithOpts(client.FromEnv, client.WithAPIVersionNegotiation())
	if err != nil {
		return nil, fmt.Errorf("failed to create Docker client: %w", err)
	}

	_, err = cli.Ping(ctx)
	if err != nil {
		return nil, fmt.Errorf("Docker is not available or not running: %w", err)
	}

	return &DockerService{cli: cli}, nil
}

func (s *DockerService) CheckDockerAvailable() error {
	ctx := context.Background()
	_, err := s.cli.Info(ctx)
	return err
}

type BuildResult struct {
	ImageName   string `json:"image_name"`
	ImageID     string `json:"image_id"`
	ImageSize   int64  `json:"image_size"`
	BuildTimeMs int64  `json:"build_time"`
}

func (s *DockerService) BuildImage(workspacePath, imageName, tag string, buildArgs map[string]string) (*BuildResult, error) {
	ctx := context.Background()
	startTime := time.Now()

	tarReader, err := s.createTar(workspacePath)
	if err != nil {
		return nil, fmt.Errorf("failed to create tar: %w", err)
	}
	defer tarReader.Close()

	buildArgsMap := make(map[string]*string)
	for k, v := range buildArgs {
		value := v
		buildArgsMap[k] = &value
	}

	opts := types.ImageBuildOptions{
		Tags:        []string{fmt.Sprintf("%s:%s", imageName, tag)},
		BuildArgs:   buildArgsMap,
		Remove:      true,
		ForceRemove: true,
		PullParent:  false,
	}

	resp, err := s.cli.ImageBuild(ctx, tarReader, opts)
	if err != nil {
		return nil, fmt.Errorf("failed to build image: %w", err)
	}
	defer resp.Body.Close()

	s.streamLogs(resp.Body)

	inspect, _, err := s.cli.ImageInspectWithRaw(ctx, fmt.Sprintf("%s:%s", imageName, tag))
	if err != nil {
		return nil, fmt.Errorf("failed to inspect image: %w", err)
	}

	buildTime := time.Since(startTime).Milliseconds()

	return &BuildResult{
		ImageName:   fmt.Sprintf("%s:%s", imageName, tag),
		ImageID:     inspect.ID,
		ImageSize:   inspect.Size,
		BuildTimeMs: buildTime,
	}, nil
}

type PushResult struct {
	PushedImage string `json:"pushed_image"`
	PushTimeMs  int64  `json:"push_time"`
}

func (s *DockerService) PushImage(imageName, registryURL, username, password string) (*PushResult, error) {
	ctx := context.Background()
	startTime := time.Now()

	targetImage := imageName
	if registryURL != "" && registryURL != "" {
		targetImage = fmt.Sprintf("%s/%s", registryURL, imageName)
		err := s.cli.ImageTag(ctx, imageName, targetImage)
		if err != nil {
			return nil, fmt.Errorf("failed to tag image: %w", err)
		}
	}

	if username != "" && password != "" {
		authConfig := types.AuthConfig{
			Username: username,
			Password: password,
		}
		_, err := s.cli.RegistryLogin(ctx, authConfig)
		if err != nil {
			return nil, fmt.Errorf("failed to login to registry: %w", err)
		}
	}

	resp, err := s.cli.ImagePush(ctx, targetImage, types.ImagePushOptions{})
	if err != nil {
		return nil, fmt.Errorf("failed to push image: %w", err)
	}
	defer resp.Close()

	s.streamLogs(resp)

	pushTime := time.Since(startTime).Milliseconds()

	return &PushResult{
		PushedImage: targetImage,
		PushTimeMs:  pushTime,
	}, nil
}

func (s *DockerService) RemoveImage(imageName string) bool {
	ctx := context.Background()
	_, err := s.cli.ImageRemove(ctx, imageName, types.ImageRemoveOptions{Force: false})
	if err != nil {
		return false
	}
	return true
}

func (s *DockerService) createTar(workspacePath string) (io.ReadCloser, error) {
	pr, pw := io.Pipe()
	tw := tar.NewWriter(pw)

	go func() {
		defer pw.Close()
		defer tw.Close()

		err := filepath.Walk(workspacePath, func(path string, info os.FileInfo, err error) error {
			if err != nil {
				return err
			}

			if info.Name() == ".git" || info.Name() == "node_modules" || info.Name() == "__pycache__" {
				if info.IsDir() {
					return filepath.SkipDir
				}
