	}
	defer resp.Close()

	s.streamLogs(resp)

	pushTime := time.Since(startTime).Milliseconds()

	return &PushResult{
		PushedImage: targetImage,
		PushTimeMs:  pushTime,
	}, nil
}

func (s *DockerService) RemoveImage(imageName string) bool {
	ctx := context.Background()
	_, err := s.cli.ImageRemove(ctx, imageName, image.RemoveOptions{Force: false})
	if err != nil {
		return false
	}
	return true
}

func (s *DockerService) createTar(workspacePath string) (io.ReadCloser, error) {
	pr, pw := io.Pipe()
	tw := tar.NewWriter(pw)

	go func() {
		defer pw.Close()
		defer tw.Close()

		err := filepath.Walk(workspacePath, func(path string, info os.FileInfo, err error) error {
			if err != nil {
				return err
			}

			if info.Name() == ".git" || info.Name() == "node_modules" || info.Name() == "__pycache__" {
				if info.IsDir() {
					return filepath.SkipDir
				}
				return nil
			}

			header, err := tar.FileInfoHeader(info, info.Name())
			if err != nil {
				return err
			}

			relPath, err := filepath.Rel(workspacePath, path)
			if err != nil {
				return err
			}
			header.Name = relPath

			if err := tw.WriteHeader(header); err != nil {
				return err
			}

			if !info.IsDir() {
				file, err := os.Open(path)
				if err != nil {
					return err
				}
				defer file.Close()

				_, err = io.Copy(tw, file)
				if err != nil {
					return err
				}
			}

			return nil
		})

		if err != nil {
			pw.CloseWithError(err)
		}
	}()

	return pr, nil
}

func (s *DockerService) streamLogs(reader io.Reader) {
	decoder := json.NewDecoder(reader)
	for {
		var msg map[string]interface{}
		if err := decoder.Decode(&msg); err != nil {
			if err == io.EOF {
				break
			}
			return
		}

		if stream, ok := msg["stream"].(string); ok {
			fmt.Print(stream)
		}
		if status, ok := msg["status"].(string); ok {
			fmt.Printf("%s", status)
			if id, ok := msg["id"].(string); ok {
				fmt.Printf(": %s", id)
			}
			fmt.Println()
		}
	}
}

func (s *DockerService) ListImages() ([]image.Summary, error) {
	ctx := context.Background()
	images, err := s.cli.ImageList(ctx, image.ListOptions{
		Filters: filters.NewArgs(),
	})
	if err != nil {
		return nil, err
	}
	return images, nil
}

func (s *DockerService) ImageExists(imageName string) bool {
	ctx := context.Background()
	_, _, err := s.cli.ImageInspectWithRaw(ctx, imageName)
	return err == nil
}

