package router

import (
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"

	"github.com/agentcube/agentcube/pkg/common/types"
	"github.com/gin-gonic/gin"
)

func (s *Server) proxyToSandbox(c *gin.Context, sandboxInfo *types.SandboxInfo, path string) {
	if len(sandboxInfo.EntryPoints) == 0 {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "no entry points"})
		return
	}

	entryPoint := sandboxInfo.EntryPoints[0]
	for _, ep := range sandboxInfo.EntryPoints {
		if strings.HasPrefix(path, ep.Path) {
			entryPoint = ep
			break
		}
	}

	targetURL, err := url.Parse(entryPoint.Endpoint)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)

	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)
		req.URL.Path = path
		req.URL.RawPath = c.Request.URL.RawPath
		req.URL.RawQuery = c.Request.URL.RawQuery

		req.Host = targetURL.Host

		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}
		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		if clientIP := c.ClientIP(); clientIP != "" {
			req.Header.Set("X-Forwarded-For", clientIP)
		}

		if sandboxInfo.Kind == types.SandboxKind || sandboxInfo.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": sandboxInfo.SessionID,
				"sandbox_id": sandboxInfo.SandboxID,
			})
			if err == nil {
				req.Header.Set("Authorization", "Bearer "+token)
			}
		}

		req.Header.Set("x-agentcube-session-id", sandboxInfo.SessionID)
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sandboxInfo.SessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		if strings.Contains(err.Error(), "connection refused") {
			c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
			return
		}
		if strings.Contains(err.Error(), "timeout") {
			c.JSON(http.StatusGatewayTimeout, gin.H{"error": "sandbox timeout"})
			return
		}
		c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

